@app.route('/token/create', methods=['POST'])
def create_token():
    data = request.get_json()
    
    if not data or 'client_id' not in data:
        return jsonify({'error': 'client_id is required'}), 400
    
    token = secrets.token_urlsafe(32)
    client_id = data['client_id']
    user_id = data.get('user_id')
    scope = data.get('scope', 'read')
    expires_in = data.get('expires_in', 3600)
    
    expires_at = datetime.utcnow().timestamp() + expires_in
    expires_at_dt = datetime.fromtimestamp(expires_at)
    
    db = get_db()
    db.execute(
        '''
        INSERT INTO access_tokens (token, client_id, user_id, scope, expires_at)
        VALUES (?, ?, ?, ?, ?)
        ''',
        (token, client_id, user_id, scope, expires_at_dt)
    )
    db.commit()
    db.close()
    
    return jsonify({
        'access_token': token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scope': scope
    })

@app.route('/token/revoke', methods=['POST'])
def revoke_token():
    data = request.get_json()
    
    if not data or 'token' not in data:
        return jsonify({'error': 'token is required'}), 400
    
    token = data['token']
    
    db = get_db()
    cursor = db.execute('UPDATE access_tokens SET revoked = 1 WHERE token = ?', (token,))
    db.commit()
    
    if cursor.rowcount > 0:
        db.close()
        return jsonify({'message': 'Token revoked successfully'})
    
    db.close()
    return jsonify({'error': 'Token not found'}), 404

@app.route('/token/introspect', methods=['POST'])
def introspect_token():
    data = request.get_json()
    
    if not data or 'token' not in data:
        return jsonify({'error': 'token is required'}), 400
    
    token = data['token']
    token_info = validate_token(token)
    
    if token_info['valid']:
        return jsonify({
            'active': True,
            'client_id': token_info['client_id'],
            'user_id': token_info['user_id'],
            'scope': token_info['scope'],
            'exp': int(datetime.fromisoformat(token_info['expires_at']).timestamp())
        })
    
    return jsonify({'active': False})

